INSERT INTO `wp_olthem_email_templates` VALUES (1,'création_atelier','atelier_admin','Demande d\'atelier reçue','L\'utilisateur [USERNAME] vient de créer une demande de programmation d\'atelier.\r\n\r\nLieu de l\'événement : [LIEU]\r\n\r\nThématique de l\'atelier : [THEMATIQUE]\r\nPériode de programmation souhaitée : entre le [start_date] et le [end_date]\r\nNombre de participants estimé : +[nb_participants]\r\n\r\nPersonne de contact : [prenom] [nom]\r\nAdresse e-mail : [email]\r\nTéléphone : [telephone]','2026-04-15 00:11:21');
INSERT INTO `wp_olthem_email_templates` VALUES (2,'reset_password','reset_password','Othem - Réinitialisation de mot de passe','Bonjour [prenom] [nom],\r\n\r\nVous avez demandé la réinitialisation de votre mot de passe.\r\nCliquez sur le lien suivant pour choisir un nouveau mot de passe (valable 1 heure) :\r\n\r\n[RESET_LINK]\r\n\r\nSi vous n\'êtes pas à l\'origine de cette demande, ignorez cet email.','2026-04-15 15:12:43');
