INSERT INTO `wp_postmeta` VALUES (324,41,'Builder_0_subsection_9_text','Que se passe-t-il derrière l’écran entre le moment où nous terminons de regarder une vidéo et celui où Youtube ou Netflix nous en propose une nouvelle ? Comment Spotify fait-il pour déterminer les artistes ou les chansons qui pourraient nous plaire ? Les algorithmes de recommandation sont au coeur des plateformes numériques délivrant des contenus commerciaux, culturels et informationnels et façonnent l’environnement médiatique contemporain. Malgré leur influence sur les pratiques médiatiques, ils restent largement opaques pour les utilisateurs qui nourrissent espoirs et peurs les concernant.\r\n\r\nAction Médias Jeunes propose aux participant.e.s de répondre eux-mêmes à ces questions en créant un algorithme de recommandation sur papier à partir de données concernant des vidéos en ligne et leurs audiences. Les participant.e.s se confrontent à leurs représentations à propos des algorithmes tout en appréhendant certains principes de base du fonctionnement des systèmes algorithmiques.\r\n\r\nCette animation peut notamment s’inscrire dans le cadre d’un cours de mathématiques.\r\n\r\nDÉTAILS PRATIQUES\r\n<ul>\r\n 	<li>Durée : entre 2 et 4 heures de cours</li>\r\n 	<li>Nombre : de 6 à 25 jeunes</li>\r\n 	<li>Besoin particulier : une salle de classe ou au Mundaneum</li>\r\n 	<li>Prix: gratuit!</li>\r\n</ul>\r\nInformation et réservation : gaetan.santarelli@mundaneum.be');
