INSERT INTO `wp_postmeta` VALUES (426,43,'Builder_0_subsection_1_text','J’en peux plus de toutes ces news si déprimantes qui disent tout et n’importe quoi ! Je rêve d’autre chose… J’veux de la vraie info, des trucs qui me parlent, pas un défilé putaclic…\r\n\r\nLes médias, sont vraiment libres ? Parfois j’ai des doutes… Et puis c’est quoi la place des citoyens là-dedans ? Des gens comme toi et moi…\r\n\r\nFaudrait qu’on en parle ensemble, journalistes et citoyens réunis…qu’on se mette toutes et tous autour de la table pour avancer, parce que là, ça urge !');
