INSERT INTO `wp_postmeta` VALUES (452,43,'Builder_0_subsection_6_text','<p data-start=\"0\" data-end=\"274\">Revivez cette journée d’échanges organisée au Mundaneum le 21 avril 2022, qui a rassemblé jeunes et professionnels autour de questions essentielles : <em data-start=\"150\" data-end=\"274\">qu’est-ce qu’un média ? comment (re)construire la confiance envers les médias ? quelle place pour le citoyen aujourd’hui ?</em></p>\r\n<p data-start=\"276\" data-end=\"458\">Sans langue de bois, journalistes, formateurs·trices et expert·es en éducation aux médias ont partagé leurs points de vue et expériences, ouvrant le dialogue avec les participant·es.</p>\r\n<p data-start=\"460\" data-end=\"619\">Destinée aux 15-25 ans, cette rencontre a alterné entre moments d’échanges et ateliers pratiques, favorisant la réflexion critique et l’expression de chacun·e.</p>');
