INSERT INTO `wp_postmeta` VALUES (478,43,'Builder_0_subsection_10_text','En partenariat avec Actions médias jeunes, nous vous proposons des ateliers gratuits\r\n<ul>\r\n 	<li>Crée ton média</li>\r\n 	<li>C’est pas sourcé !</li>\r\n</ul>\r\nAction Médias Jeunes propose aux participants de se plonger au cœur de la fabrication de l’information. Les jeunes sont divisés en plusieurs petits groupes et chaque groupe correspond à une rédaction de presse écrite. Face à un fait d’actualité créé de toutes pièces, chaque rédaction a la lourde tâche de faire des choix parmi les sources proposées afin de donner l’information la plus pertinente à leurs lecteur·rices. Mais attention, l’information n’attend pas et nos jeunes journalistes en herbe doivent apprendre à travailler sous la pression du temps, l’ennemi numéro un de l’information vérifiée.\r\n\r\nCette animation très concrète amène les jeunes à une réflexion autour de la fiabilité de l’information, du\r\nrecoupage des sources, des médias d’information en général ainsi que sur la question des fake news.\r\nTrouver une bonne information sourcée, vérifiée et pertinente lors de nos recherches sur un sujet spécifique n’est pas toujours chose aisée. Ce jeu de société est l’occasion d’amener une réflexion sur ces thématiques dès le plus jeune âge afin d’éveiller son esprit critique et d’attraper les bons réflexes le plus tôt\r\npossible !\r\n\r\nA vivre en classe ou en groupe pour des jeunes de 15-25 ans\r\n\r\nPlus d’infos info@mundaneum.be');
