INSERT INTO `wp_postmeta` VALUES (917,44,'Builder_0_subsection_5_paragraphename','Journée évènement');
INSERT INTO `wp_postmeta` VALUES (918,44,'_Builder_0_subsection_5_paragraphename','field_69c72efc6a921');
INSERT INTO `wp_postmeta` VALUES (919,44,'Builder_0_subsection_6_text','Le 29 mars 2023, nous avons organisé une journée événement autour de la thématique de la diversité dans les médias d’information avec :\r\n\r\ndes intervenants de Médor\r\nFlorence Coppenolle\r\nune modération par l’une des journalistes de Engaje (Fatimetou Sow, ex-présentatrice du JT en Mauritanie et en exil pour raisons politiques)\r\n\r\nUn World Café a permis aux étudiants de débattre en groupes plus réduits mais également de dégager des pistes de propositions à faire aux médias existants.\r\nAu programme de l’après-midi, trois ateliers pratiques\r\n– Action Médias Jeunes\r\n– 2 ateliers proposés par le Mundaneum : quizz de la diversité et création médiatique (radio) sur la diversité');
INSERT INTO `wp_postmeta` VALUES (920,44,'_Builder_0_subsection_6_text','field_69c4d54bbf536');
