INSERT INTO `wp_postmeta` VALUES (937,44,'Builder_0_subsection_9_ignorespacing','0');
INSERT INTO `wp_postmeta` VALUES (938,44,'_Builder_0_subsection_9_ignorespacing','field_69cbeb348ce06');
INSERT INTO `wp_postmeta` VALUES (939,44,'Builder_0_subsection_10_paragraphename','Dossier pédagogique');
INSERT INTO `wp_postmeta` VALUES (940,44,'_Builder_0_subsection_10_paragraphename','field_69c72efc6a921');
INSERT INTO `wp_postmeta` VALUES (941,44,'Builder_0_subsection_11_text','Dans ce dossier pédagogique « On n’a que l’info qu’on se donne », comme son nom l’indique, on va réfléchir à la manière dont les médias traitent la notion de diversité, quel angle ils posent, comment ils la représentent et par quel trou de serrure on regarde, nous consommatrices et consommateurs. On questionnera aussi la manière dont sont constituées les rédactions de ces médias d’informations et comment elles fonctionnent en tant que système. On finira par quelques pistes de solutions et de réflexions ainsi que par des ateliers à faire en classe pour sensibiliser les jeunes à toutes ces notions et cette réalité.\r\n\r\nBonne lecture !');
INSERT INTO `wp_postmeta` VALUES (942,44,'_Builder_0_subsection_11_text','field_69c4d54bbf536');
