INSERT INTO `wp_postmeta` VALUES (974,43,'Builder_0_subsection_17_paragraphename','Slam sur la thématique - Serial D\'rimeur');
INSERT INTO `wp_postmeta` VALUES (975,43,'_Builder_0_subsection_17_paragraphename','field_69c72efc6a921');
INSERT INTO `wp_postmeta` VALUES (976,43,'Builder_0_subsection_18_text','<p style=\"text-align: left;\">Il n’y a pas que des journalistes qui couvrent les faits brûlants</p>\r\n<p style=\"text-align: left;\">Qui sont là quand l’ampleur des dégâts se mesure en flaques de sang</p>\r\n<p style=\"text-align: left;\">Dont les titres annoncent une vague de clics massive et imminente</p>\r\n<p style=\"text-align: left;\">Dont les bandes sons des reportages rappellent certains films d’épouvante</p>\r\n<p style=\"text-align: left;\">Qui déroulent la liste des problèmes majeurs en les accentuant</p>\r\n<p style=\"text-align: left;\">Qui abusent du sensationnalisme, accroissent l’anxiété des gens</p>\r\n<p style=\"text-align: left;\">Qui mettent le focus sur les news qui vont rythmer nos quotidiens</p>\r\n<p style=\"text-align: left;\">Il y a d’autres journalismes qui, au lieu de nous cibler, nous veulent du bien</p>\r\n<p style=\"text-align: left;\">Ceux qui proposent plus que des miroirs mais des fenêtres vers le changement</p>\r\n<p style=\"text-align: left;\">Ceux qui n’induisent pas dans nos têtes qu’il y a les bons puis les méchants</p>\r\n<p style=\"text-align: left;\">Ceux qui ne surlignent pas au fluo ségrégations ou couleurs de peaux</p>\r\n<p style=\"text-align: left;\">Ceux qui n’attribuent pas à un peuple la misère du monde, le chaos</p>\r\n<p style=\"text-align: left;\">Ceux qui tentent de défaire les nœuds plutôt que de figer un conflit</p>\r\n<p style=\"text-align: left;\">Ceux qui construisent des passerelles afin de relier nos esprits</p>\r\n<p style=\"text-align: left;\">Ceux qui cartographient le site avant de le nommer « labyrinthe »</p>\r\n<p style=\"text-align: left;\">Ceux qui ne dénaturent pas la toile ni l’artiste qui l’a peinte</p>\r\n<p style=\"text-align: left;\">Le journalisme constructif, entre autres, compose avec ces éléments</p>\r\n<p style=\"text-align: left;\">Nous suggère une autre lecture, d’autres lunettes face aux événements</p>\r\n<p style=\"text-align: left;\">Sans nier l’actu chaude au cœur des préoccupations</p>\r\n<p style=\"text-align: left;\">Mais en ouvrant le champ des possibles quant à des pistes de solutions</p>\r\n<p style=\"text-align: left;\">Réinstaurons cette confiance entre nos médias et nous, citoyens</p>\r\n<p style=\"text-align: left;\">Pour empêcher une méfiance croissante envers ces acteurs de terrain</p>\r\n<p style=\"text-align: left;\">Nous poussant dans nos retranchements à mener nos enquêtes maison</p>\r\n<p style=\"text-align: left;\">Quitte à laisser certaines théories peser lourd dans nos convictions</p>\r\n<p style=\"text-align: left;\">Il est temps de panser plus que d’enfoncer les plumes dans les plaies</p>\r\n<p style=\"text-align: left;\">Ces plumes se doivent d’être légères plus que teintées de culpabilités</p>\r\n<p style=\"text-align: left;\">D’éviter de rappeler au lecteur l’envergure de ses prochaines luttes</p>\r\n<p style=\"text-align: left;\">De lui refiler des ailes sans le faire songer à ses prochaines chutes</p>\r\n<p style=\"text-align: left;\">On sait que personne n’est à l’abri face à la menace climatique</p>\r\n<p style=\"text-align: left;\">Mais on peut surfer sur autre chose que sur nos peurs et nos paniques</p>\r\n<p style=\"text-align: left;\">Rendre quelques sourires aux faces n’est pas privilège des bisounours</p>\r\n<p style=\"text-align: left;\">Il est aussi bon de savoir qu’on a autre chose que la mort aux trousses</p>\r\n<p style=\"text-align: left;\">Il y a tant de plateformes existantes prêtes à confronter nos idées</p>\r\n<p style=\"text-align: left;\">Tant de médias alternatifs permettant l’échange de bons procédés</p>\r\n<p style=\"text-align: left;\">Raison de plus pour nous impliquer, voir au-delà des constats navrants</p>\r\n<p style=\"text-align: left;\">Cessons de nous dire « mais qu’avons-nous fait ? », optons pour « qu’est-ce qu’on fait maintenant ? »</p>\r\n&nbsp;\r\n<p style=\"text-align: left;\"><strong>Serial D’rimeur</strong> (avril 2022)</p>');
