INSERT INTO `wp_postmeta` VALUES (3466,313,'Builder_1_text_bloc','<p style=\"text-align: center;\" data-start=\"56\" data-end=\"232\">Merci [<strong>USERNAME</strong>], nous avons bien reçu votre demande. Un responsable prendra contact prochainement avec [<strong>prenom</strong>] [<strong>nom</strong>] afin de préciser la date et les modalités de l’événement.</p>\r\n<p style=\"text-align: center;\">Lieu de l’événement : [<strong>ETABLISSEMENT</strong>], [<strong>ADRESSE</strong>] – [<strong>CODE POSTAL</strong>] [<strong>LOCALITE</strong>] / [<strong>MUNDANEUM, Rue de Nimy, 76 - 7000 Mons</strong>]</p>\r\n<p style=\"text-align: center;\">Thématique de l’atelier : [<strong>THEMATIQUE</strong>]<br data-start=\"392\" data-end=\"395\" />Période de programmation souhaitée : <strong>entre le</strong> [<strong>start_date</strong>] <strong>et le</strong> [<strong>end_date</strong>]\r\nNombre de participants estimé : <strong>+</strong>[<strong>nb_participants</strong>]</p>\r\n<p style=\"text-align: center;\">Personne de contact : [<strong>prenom</strong>] [<strong>nom</strong>]\r\nAdresse e-mail : [<strong>email</strong>]\r\nTéléphone : [<strong>telephone</strong>]</p>\r\n<p style=\"text-align: center;\">Afficher l’événement sur le site : [<strong>displayEvent</strong>]<br data-start=\"574\" data-end=\"577\" />Afficher le contact sur le site : [<strong>displayContact</strong>]</p>\r\n<p style=\"text-align: center;\" data-start=\"718\" data-end=\"902\">Vous pouvez annuler ou modifier les données de l’atelier à tout moment via votre espace utilisateur, en cliquant sur votre nom dans le menu principal, jusqu’à sa validation définitive.</p>');
